-- RLS: tasks — can see tasks you created, are assigned to, or manage as assistant
CREATE POLICY "tasks_access" ON tasks
  USING (
    created_by = auth.email()
    OR EXISTS (
      SELECT 1 FROM task_assignees
      WHERE task_assignees.task_id = tasks.id
        AND task_assignees.assignee_email = auth.email()
    )
    OR EXISTS (
      SELECT 1 FROM user_assistants
      WHERE user_assistants.assistant_email = auth.email()
        AND (
          tasks.created_by = user_assistants.manager_email
          OR EXISTS (
            SELECT 1 FROM task_assignees ta2
            WHERE ta2.task_id = tasks.id
              AND ta2.assignee_email = user_assistants.manager_email
          )
        )
    )
  );

-- RLS: task_assignees
CREATE POLICY "task_assignees_access" ON task_assignees
  USING (
    assignee_email = auth.email()
    OR EXISTS (
      SELECT 1 FROM tasks
      WHERE tasks.id = task_assignees.task_id
        AND tasks.created_by = auth.email()
    )
    OR EXISTS (
      SELECT 1 FROM user_assistants
      WHERE user_assistants.assistant_email = auth.email()
        AND (
          task_assignees.assignee_email = user_assistants.manager_email
          OR EXISTS (
            SELECT 1 FROM tasks t2
            WHERE t2.id = task_assignees.task_id
              AND t2.created_by = user_assistants.manager_email
          )
        )
    )
  );

