-- 5. RPC: aggregate stats
CREATE OR REPLACE FUNCTION get_campaign_stats()
RETURNS TABLE (campaign_id UUID, delivered_count BIGINT, open_count BIGINT, click_count BIGINT, bounce_count BIGINT)
LANGUAGE SQL SECURITY DEFINER AS $$
  SELECT
    campaign_id,
    COUNT(DISTINCT CASE WHEN event = 'delivered' THEN email END),
    COUNT(DISTINCT CASE WHEN event = 'open'      THEN email END),
    COUNT(DISTINCT CASE WHEN event = 'click'     THEN email END),
    COUNT(DISTINCT CASE WHEN event = 'bounce'    THEN email END)
  FROM email_events
  WHERE campaign_id IS NOT NULL
  GROUP BY campaign_id;
$$;

-- 6. RPC: per-recipient status
CREATE OR REPLACE FUNCTION get_campaign_recipients(p_campaign_id UUID)
RETURNS TABLE (
  contact_id UUID, contact_name TEXT, contact_email TEXT, company TEXT,
  delivered_at TIMESTAMPTZ, first_opened_at TIMESTAMPTZ, open_count BIGINT,
  last_clicked_at TIMESTAMPTZ, bounced_at TIMESTAMPTZ
)
LANGUAGE SQL SECURITY DEFINER AS $$
  SELECT
    c.id, c.name, c.email, c.company,
    MAX(CASE WHEN ee.event = 'delivered' THEN ee.occurred_at END),
    MIN(CASE WHEN ee.event = 'open'      THEN ee.occurred_at END),
    COUNT(CASE WHEN ee.event = 'open'    THEN 1 END),
    MAX(CASE WHEN ee.event = 'click'     THEN ee.occurred_at END),
    MAX(CASE WHEN ee.event = 'bounce'    THEN ee.occurred_at END)
  FROM interaction_logs il
  JOIN contacts c ON c.id = il.contact_id
  LEFT JOIN email_events ee
    ON ee.campaign_id = il.campaign_id AND ee.email = c.email
  WHERE il.campaign_id = p_campaign_id AND il.type = 'email'
  GROUP BY c.id, c.name, c.email, c.company
  ORDER BY MIN(CASE WHEN ee.event = 'open' THEN ee.occurred_at END) ASC NULLS LAST, c.name;
$$;

