-- Harden link_subscriber_to_contact against search_path hijacking
-- (advisor: function_search_path_mutable)

CREATE OR REPLACE FUNCTION link_subscriber_to_contact()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY INVOKER
SET search_path = public, pg_temp
AS $$
BEGIN
  IF NEW.email IS NULL OR NEW.deleted_at IS NOT NULL THEN
    RETURN NEW;
  END IF;

  UPDATE newsletter_subscribers
  SET contact_id = NEW.id
  WHERE contact_id IS NULL
    AND lower(trim(email::text)) = lower(trim(NEW.email));

  RETURN NEW;
END;
$$;

