-- 5. Trigger function: keep last_activity_at in sync with interaction_logs
CREATE OR REPLACE FUNCTION update_contact_last_activity()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  target_contact_id uuid;
BEGIN
  -- Which contact needs recalc? On DELETE use OLD, otherwise NEW
  target_contact_id := COALESCE(NEW.contact_id, OLD.contact_id);
  IF target_contact_id IS NULL THEN
    RETURN NULL;
  END IF;

  UPDATE contacts
  SET last_activity_at = COALESCE(
    (SELECT MAX(il.created_at) FROM interaction_logs il
     WHERE il.contact_id = target_contact_id
       AND il.type IN ('note','meeting','email')),
    created_at
  )
  WHERE id = target_contact_id;

  -- If UPDATE moved log between contacts (rare), also recalc old one
  IF TG_OP = 'UPDATE' AND OLD.contact_id IS NOT NULL AND OLD.contact_id <> NEW.contact_id THEN
    UPDATE contacts
    SET last_activity_at = COALESCE(
      (SELECT MAX(il.created_at) FROM interaction_logs il
       WHERE il.contact_id = OLD.contact_id
         AND il.type IN ('note','meeting','email')),
      created_at
    )
    WHERE id = OLD.contact_id;
  END IF;

  RETURN NULL;
END;
$$;

-- 6. Trigger: fire on any row change in interaction_logs
DROP TRIGGER IF EXISTS trg_update_contact_last_activity ON interaction_logs;
CREATE TRIGGER trg_update_contact_last_activity
  AFTER INSERT OR UPDATE OR DELETE ON interaction_logs
  FOR EACH ROW EXECUTE FUNCTION update_contact_last_activity();

