-- Photos are also a signal of "recent interaction" with a contact — a 合照 upload
-- today should bump that contact to the top of the list even without an explicit
-- interaction_log entry. The existing trigger on interaction_logs only counts
-- note/meeting/email; photos go to a separate table (contact_photos) and are
-- currently invisible to last_activity_at.
--
-- Strategy: separate trigger on contact_photos that, on INSERT or DELETE, takes
-- GREATEST(current last_activity_at, MAX(photo.created_at)) and writes it back.
-- Uses the SAME column, so default sort keeps working transparently.

CREATE OR REPLACE FUNCTION update_contact_last_activity_from_photo()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  target_contact_id uuid;
BEGIN
  target_contact_id := COALESCE(NEW.contact_id, OLD.contact_id);
  IF target_contact_id IS NULL THEN
    RETURN NULL;
  END IF;

  -- Recalc: max(interaction_logs in {note,meeting,email}) vs max(contact_photos.created_at) vs created_at
  UPDATE contacts
  SET last_activity_at = GREATEST(
    COALESCE(
      (SELECT MAX(il.created_at) FROM interaction_logs il
       WHERE il.contact_id = target_contact_id
         AND il.type IN ('note','meeting','email')),
      created_at
    ),
    COALESCE(
      (SELECT MAX(cp.created_at) FROM contact_photos cp
       WHERE cp.contact_id = target_contact_id),
      created_at
    )
  )
  WHERE id = target_contact_id;

  RETURN NULL;
END;
$$;

