-- Backfill: recalculate last_activity_at for all contacts that may have been
-- incorrectly set by newsletter logs with the old 'sendgrid' value.
UPDATE contacts c
SET last_activity_at = GREATEST(
  COALESCE(
    (SELECT MAX(il.created_at) FROM interaction_logs il
     WHERE il.contact_id = c.id
       AND il.type IN ('note','meeting','email')
       AND (il.send_method IS NULL OR il.send_method NOT IN ('sendgrid','newsletter'))),
    c.created_at
  ),
  COALESCE(
    (SELECT MAX(cp.created_at) FROM contact_photos cp
     WHERE cp.contact_id = c.id),
    c.created_at
  )
)
WHERE c.deleted_at IS NULL;
